mapper.select:
select com_name
from company
where com_id=#{comId}

select f.for_id as forId, f.com_id as comId, f.for_code as forCode, f.for_title as forTitle, f.for_content as forContent, f.for_status as forStatus, f.created_at as createdAt, f.updated_ad as updatedAt, c.com_name as comName from appr_form f left outer join company c on f.com_id = c.com_id
and f.com_id = #{comId}
and f.for_status = #{forStatus}
and ( f.for_code like concat('%',#{keyword},'%') or f.for_title like concat('%', #{keyword},'%') )
order by f.for_id desc limit #{pstartno}, #{onepagelist}

select count(*)
from appr_form


		and com_id = #{comId}


		and for_status = #{forStatus}


		and (
			for_code like concat('%',#{keyword},'%')
			or for_title like concat('%', #{keyword},'%')
		)

select * 
from appr_form


		and f.com_id = #{comId}


		and f.for_status = #{forStatus}


		f.for_code like concat('%',#{keyword},'%')
		or f.for_title like concat('%', #{keyword},'%')


order by for_id desc limit #{pstartno}
